{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void TestInitialize()
        {
            _sut = new NotificationService();
            // Drain any existing notifications from the static queue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendNotification_ThenReceive_ReturnsNotificationWithCorrectProperties()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("Student", result.EntityType);
            Assert.AreEqual("1", result.EntityId);
            Assert.AreEqual("CREATE", result.Operation);
            Assert.AreEqual("Admin", result.CreatedBy);
            Assert.IsFalse(result.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Course", "101", EntityOperation.UPDATE);

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("System", result.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("New Student 'John Doe' has been created", result.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.UPDATE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("Student 'John Doe' has been updated", result.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.DELETE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("Student 'John Doe' has been deleted", result.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 42) has been created", result.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateWithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "101", EntityOperation.UPDATE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("Course (ID: 101) has been updated", result.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteWithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Department", "5", EntityOperation.DELETE);

            var result = _sut.ReceiveNotification();

            Assert.AreEqual("Department (ID: 5) has been deleted", result.Message);
        }

        [TestMethod]
        public void SendAndReceive_MultipleNotifications_FifoOrder()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("Department", third.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_AfterAllConsumed_ReturnsNull()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.ReceiveNotification(); // consume it

            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation but should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            _sut.Dispose();
            // Calling dispose again should also not throw
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToNonDefault()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var result = _sut.ReceiveNotification();

            Assert.AreNotEqual(default, result.CreatedAt);
        }

        [TestMethod]
        public void SendNotification_TwoArgOverload_CallsFiveArgOverload()
        {
            // The 2-arg overload passes null for entityDisplayName
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("Student", result.EntityType);
            Assert.AreEqual("TestUser", result.CreatedBy);
            // Without display name, message uses ID format
            Assert.AreEqual("New Student (ID: 1) has been created", result.Message);
        }
    }
}

