namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_ReturnsViewResult()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_ReturnsListOfEnrollmentDateGroups()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count > 0);
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            // Add students with same enrollment date
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "C", LastName = "Three", EnrollmentDate = DateTime.Parse("2021-01-01") }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            Assert.AreEqual(2, model.Count);
            var group2020 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2020-01-01"));
            Assert.AreEqual(2, group2020.StudentCount);
            var group2021 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2021-01-01"));
            Assert.AreEqual(1, group2021.StudentCount);
        }

        [TestMethod]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            _controller.Contact();

            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            _controller.Unauthorized();

            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

