using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);

            // Drain any existing notifications from the static queue
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue a notification via the service
            using var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
            // The result should contain notification data
            var value = result.Value;
            Assert.IsNotNull(value);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccessTrue()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsNotNull(result.Value);
            // Verify the result contains success = true
            var resultType = result.Value.GetType();
            var successProp = resultType.GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(result.Value));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10Notifications()
        {
            // Enqueue more than 10 notifications
            using var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            // Verify the result type has a count property
            var resultType = result.Value.GetType();
            var countProp = resultType.GetProperty("count");
            Assert.IsNotNull(countProp);
            var count = (int)countProp.GetValue(result.Value);
            Assert.IsTrue(count <= 10);
        }

        [TestMethod]
        public void GetNotifications_ReturnsSuccessTrue()
        {
            var result = _controller.GetNotifications();

            var resultType = result.Value.GetType();
            var successProp = resultType.GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(result.Value));
        }
    }
}

