            Assert.AreEqual("Calculus", calculus.Title);
            Assert.AreEqual(4, calculus.Credits);
        }

        [TestMethod]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            var departments = context.Departments.ToList();
            Assert.IsTrue(departments.All(d => d.InstructorID != null));
        }

        [TestMethod]
        public void Initialize_EnrollmentsHaveGrades()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            // Some enrollments have grades, some don't
            var enrollments = context.Enrollments.ToList();
            Assert.IsTrue(enrollments.Any(e => e.Grade != null));
            Assert.IsTrue(enrollments.Any(e => e.Grade == null));
        }

        [TestMethod]
        public void Initialize_OfficeAssignmentsHaveLocations()
        {
            using var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            var offices = context.OfficeAssignments.ToList();
            Assert.IsTrue(offices.Any(o => o.Location == "Smith 17"));
            Assert.IsTrue(offices.Any(o => o.Location == "Gowan 27"));
            Assert.IsTrue(offices.Any(o => o.Location == "Thompson 304"));
        }

        [TestMethod]
        public void Initialize_ExistingStudents_SkipsSeeding()
        {
            using var context = TestHelpers.CreateContext();
            // Pre-add a student so Initialize detects existing data
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = System.DateTime.Parse("2020-01-01")
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            // Should still have only 1 student since seeding was skipped
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual(0, context.Courses.Count());
        }
    }
}

